const BASE = 'https://www.boursorama.com';
const MARKETS = [
  { id: 2201, label: 'A' },
  { id: 2202, label: 'B' },
  { id: 2203, label: 'C' },
];

const headers = {
  'User-Agent': 'Mozilla/5.0 (n8n; +https://n8n.io) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120 Safari/537.36',
  'Accept-Language': 'fr-FR,fr;q=0.9,en;q=0.8',
};

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function httpGet(url) {
  const maxTry = 4;
  for (let i = 1; i <= maxTry; i++) {
    try {
      return await this.helpers.httpRequest({
        method: 'GET',
        url,
        headers,
        timeout: 30000,
        followRedirect: true,
      });
    } catch (e) {
      if (i === maxTry) throw e;
      await sleep(400 * i);
    }
  }
}

function decodeHtml(s) {
  if (!s) return '';
  return s
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#(\d+);/g, (_, n) => {
      const code = parseInt(n, 10);
      if (!Number.isFinite(code)) return _;
      try { return String.fromCharCode(code); } catch { return _; }
    });
}

function stripTags(s) {
  return (s || '').replace(/<[^>]*>/g, '');
}

function getMaxPage(html) {
  const re = /\/bourse\/actions\/cotations\/page-(\d+)/g;
  let max = 1;
  let m;
  while ((m = re.exec(html)) !== null) {
    const p = parseInt(m[1], 10);
    if (Number.isFinite(p)) max = Math.max(max, p);
  }
  return max;
}

function extractRows(html) {
  // On capte les liens /cours/1rPXXXX/
  const re = /<a[^>]+href="\/cours\/1rP([A-Za-z0-9]+)\/?"[^>]*>([\s\S]*?)<\/a>/g;
  const rows = [];
  let m;
  while ((m = re.exec(html)) !== null) {
    const ticker = (m[1] || '').toUpperCase().trim();
    if (!/^[A-Z0-9]{1,12}$/.test(ticker)) continue;

    const rawName = m[2] || '';
    const name = decodeHtml(stripTags(rawName)).replace(/\s+/g, ' ').trim();
    if (!name) continue;

    // Yahoo Finance Euronext Paris suffix
    const symbol = `${ticker}.PA`;
    rows.push({ Symbol: symbol, Name: name });
  }
  return rows;
}

const seen = new Map();

for (const mk of MARKETS) {
  const page1 = `${BASE}/bourse/actions/cotations/?quotation_az_filter%5Bmarket%5D=${mk.id}`;
  const html1 = await httpGet.call(this, page1);
  const maxPage = getMaxPage(html1);

  for (const r of extractRows(html1)) {
    if (!seen.has(r.Symbol)) seen.set(r.Symbol, r.Name);
  }

  for (let p = 2; p <= maxPage; p++) {
    const url = `${BASE}/bourse/actions/cotations/page-${p}?quotation_az_filter%5Bmarket%5D=${mk.id}`;
    const html = await httpGet.call(this, url);
    for (const r of extractRows(html)) {
      if (!seen.has(r.Symbol)) seen.set(r.Symbol, r.Name);
    }
    await sleep(250);
  }

  await sleep(400);
}

const out = Array.from(seen.entries())
  .map(([Symbol, Name]) => ({ Symbol, Name }))
  .sort((a, b) => a.Symbol.localeCompare(b.Symbol));

return out;
